"use client";

import { useEffect, useRef, useState, useCallback } from "react";
import ScrollReveal from "@/components/ScrollReveal";
import MenuItemCard from "./MenuItemCard";

/* ── Types ─────────────────────────────────────────────── */

interface Category {
  _id: string;
  name: string;
  slug: { current: string } | string;
  description?: string;
}

interface MenuItem {
  _id: string;
  name: string;
  description?: string;
  price: number;
  image?: string;
  category?: { _id: string; name: string; slug: { current: string } | string };
  allergens?: string[];
  tags?: string[];
  extras?: { name: string; price: number }[];
}

interface MenuContentProps {
  categories: Category[];
  items: MenuItem[];
}

function getSlug(slug: { current: string } | string | undefined): string {
  if (!slug) return "";
  if (typeof slug === "string") return slug;
  return slug.current;
}

/* ── Component ─────────────────────────────────────────── */

export default function MenuContent({ categories, items }: MenuContentProps) {
  const [activeCategory, setActiveCategory] = useState<string>(
    categories[0] ? getSlug(categories[0].slug) : ""
  );
  const sectionRefs = useRef<Map<string, HTMLElement>>(new Map());
  const tabsRef = useRef<HTMLDivElement>(null);
  const isScrolling = useRef(false);

  // Group items by category
  const itemsByCategory = new Map<string, MenuItem[]>();
  for (const cat of categories) {
    const slug = getSlug(cat.slug);
    itemsByCategory.set(
      slug,
      items.filter((item) => {
        if (!item.category) return false;
        const catSlug = getSlug(item.category.slug);
        return catSlug === slug;
      })
    );
  }

  // Items without category
  const uncategorized = items.filter((item) => !item.category);
  if (uncategorized.length > 0 && !itemsByCategory.has("autres")) {
    itemsByCategory.set("autres", uncategorized);
  }

  // Intersection Observer to highlight active tab on scroll
  const observerCallback = useCallback(
    (entries: IntersectionObserverEntry[]) => {
      if (isScrolling.current) return;
      for (const entry of entries) {
        if (entry.isIntersecting) {
          setActiveCategory(entry.target.id);
          break;
        }
      }
    },
    []
  );

  useEffect(() => {
    const observer = new IntersectionObserver(observerCallback, {
      rootMargin: "-120px 0px -60% 0px",
      threshold: 0,
    });

    sectionRefs.current.forEach((el) => observer.observe(el));
    return () => observer.disconnect();
  }, [observerCallback, categories]);

  // Scroll to category section
  const scrollToCategory = (slug: string) => {
    const el = sectionRefs.current.get(slug);
    if (!el) return;

    isScrolling.current = true;
    setActiveCategory(slug);

    el.scrollIntoView({ behavior: "smooth", block: "start" });

    // Re-enable observer after scroll completes
    setTimeout(() => {
      isScrolling.current = false;
    }, 800);
  };

  // Scroll active tab into view on mobile
  useEffect(() => {
    if (!tabsRef.current) return;
    const activeEl = tabsRef.current.querySelector("[data-active='true']");
    if (activeEl) {
      activeEl.scrollIntoView({
        behavior: "smooth",
        block: "nearest",
        inline: "center",
      });
    }
  }, [activeCategory]);

  return (
    <section className="bg-brand-dark pb-16">
      {/* Category tabs — sticky */}
      <div className="sticky top-[72px] z-30 border-b border-neutral-800 bg-brand-dark/95 backdrop-blur-md">
        <div className="mx-auto max-w-4xl px-6">
          <div
            ref={tabsRef}
            className="scrollbar-hide flex gap-1 overflow-x-auto"
          >
            {categories.map((cat) => {
              const slug = getSlug(cat.slug);
              const isActive = activeCategory === slug;
              return (
                <button
                  key={slug}
                  data-active={isActive}
                  onClick={() => scrollToCategory(slug)}
                  className={`whitespace-nowrap px-5 py-4 font-heading text-xs uppercase tracking-[0.2em] transition-colors ${isActive
                    ? "border-b-2 border-brand-orange text-brand-cream"
                    : "border-b-2 border-transparent text-brand-cream/40 hover:text-brand-cream/70"
                    }`}
                >
                  {cat.name}
                </button>
              );
            })}
          </div>
        </div>
      </div>

      {/* Menu sections */}
      <div className="mx-auto max-w-4xl px-6 pt-12">
        {categories.map((cat, catIndex) => {
          const slug = getSlug(cat.slug);
          const catItems = itemsByCategory.get(slug) ?? [];
          if (catItems.length === 0) return null;

          return (
            <section
              key={slug}
              id={slug}
              ref={(el) => {
                if (el) sectionRefs.current.set(slug, el);
              }}
              className={catIndex > 0 ? "mt-16 scroll-mt-32" : "scroll-mt-32"}
            >
              {/* Category header */}
              <ScrollReveal stagger staggerChildren={0.1}>
                <span className="font-heading text-xs uppercase tracking-[0.3em] text-brand-orange block mb-2">
                  {cat.name}
                </span>
                <div className="mt-2 mb-4 h-px w-10 bg-brand-orange/50" />
                {cat.description && (
                  <p className="text-sm text-brand-cream/60 max-w-lg mb-8">
                    {cat.description}
                  </p>
                )}

                {/* Items */}
                <div className="divide-y divide-brand-cream/10">
                  {catItems.map((item) => (
                    <ScrollReveal key={item._id}>
                      <div className="py-4 hover:bg-brand-orange/5 transition-colors px-2 -mx-2 rounded-sm group">
                        <MenuItemCard item={item} />
                      </div>
                    </ScrollReveal>
                  ))}
                </div>
              </ScrollReveal>
            </section>
          );
        })}

        {/* Uncategorized items */}
        {uncategorized.length > 0 && (
          <section
            id="autres"
            ref={(el) => {
              if (el) sectionRefs.current.set("autres", el);
            }}
            className="mt-16 scroll-mt-32"
          >
            <ScrollReveal stagger staggerChildren={0.1}>
              <span className="font-heading text-xs uppercase tracking-[0.3em] text-brand-orange block mb-2">
                Autres
              </span>
              <div className="mt-2 mb-8 h-px w-10 bg-brand-orange/50" />

              <div className="divide-y divide-brand-cream/10">
                {uncategorized.map((item) => (
                  <ScrollReveal key={item._id}>
                    <div className="py-4 hover:bg-brand-orange/5 transition-colors px-2 -mx-2 rounded-sm group">
                      <MenuItemCard item={item} />
                    </div>
                  </ScrollReveal>
                ))}
              </div>
            </ScrollReveal>
          </section>
        )}
      </div>
    </section>
  );
}
